module counter_with_set(CLK, SET, EN, COUNT);
input CLK, SET, EN;
output reg [3:0] COUNT;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge SET or posedge dbg_halt) begin
    if (SET)
        COUNT <= 4'b1000;
    else if (EN)
        COUNT <= COUNT + 1;
end

endmodule
